// Input: items[0].json contains your CSV string
// Output: one item per row as JSON

const csvString = $input.first().json.data;   // whole CSV string comes here
const rows = csvString.split("\r\n").filter(r => r.trim() !== ""); // split by line

// First row is headers
const headers = rows[0].split(",");

// Remaining rows are data
const output = [];

for (let i = 1; i < rows.length; i++) {
  const values = rows[i].split(",");
  let rowObj = {};

  headers.forEach((header, index) => {
    rowObj[header] = values[index] || "";
  });

  output.push({ json: rowObj });
}

return output;

// n8n Function node: flatten aggregate data[] and convert Google Drive/Docs links to direct download URLs

const out = [];

// Helper: convert Google Drive/Docs share link → direct download link
function toDownloadUrl(link) {
  if (!link) return "";

  let fileId = "";

  // Case 1: Google Docs (convert to PDF)
  let match = link.match(/document\/d\/([^/]+)/);
  if (match && match[1]) {
    fileId = match[1];
    return `https://docs.google.com/document/d/${fileId}/export?format=pdf`;
  }

  // Case 2: Google Sheets (convert to PDF)
  match = link.match(/spreadsheets\/d\/([^/]+)/);
  if (match && match[1]) {
    fileId = match[1];
    return `https://docs.google.com/spreadsheets/d/${fileId}/export?format=pdf`;
  }

  // Case 3: Google Slides (convert to PDF)
  match = link.match(/presentation\/d\/([^/]+)/);
  if (match && match[1]) {
    fileId = match[1];
    return `https://docs.google.com/presentation/d/${fileId}/export/pdf`;
  }

  // Case 4: Google Drive /d/{fileId}/
  match = link.match(/\/d\/([^/]+)\//);
  if (match && match[1]) {
    fileId = match[1];
    return `https://drive.google.com/uc?export=download&id=${fileId}`;
  }

  // Case 5: Google Drive ?id={fileId}
  match = link.match(/[?&]id=([^&]+)/);
  if (match && match[1]) {
    fileId = match[1];
    return `https://drive.google.com/uc?export=download&id=${fileId}`;
  }

  // Default: return as-is
  return link;
}

for (const row of items[0].json.data) {
  const originalLink = row["Resume link"] || "";

  out.push({
    json: {
      Name: row["Name"] || "",
      ResumeLink_original: originalLink,
      ResumeDownloadUrl: toDownloadUrl(originalLink),
      ProcessFlag: row["toProcess"] || "TO_PROCESS",
      Timestamp: new Date().toISOString()
    }
  });
}

return out;

// Parse AI output from common LLM response shapes and strip code fences
const out = [];

for (const item of items) {
  const j = item.json;
  // try common places for the model text
  let raw = "";
  if (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content) {
    raw = j.choices[0].message.content;
  } else if (j.text) {
    raw = j.text;
  } else if (j.output) {
    raw = j.output;
  } else if (j.aiOutput) {
    raw = j.aiOutput;
  } else if (j["AI Agent"]) {
    raw = j["AI Agent"];
  } else {
    // fallback: stringify whole item
    raw = JSON.stringify(j);
  }

  // remove code fences like ```json ... ```
  raw = raw.replace(/^\s*```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim();

  // try to extract first {...} block
  const bracketMatch = raw.match(/\{[\s\S]*\}/);
  let parsed = null;
  try {
    parsed = bracketMatch ? JSON.parse(bracketMatch[0]) : JSON.parse(raw);
  } catch (err) {
    // return parse error (we'll handle later)
    parsed = { __parseError: err.message, __raw: raw };
  }

  out.push({ json: parsed });
}

return out;

// Input: Google Sheets link as "sheetLink"
const link =$input.first().json.body.csv ;  

// Extract File ID from /d/xxxx/
const fileIdMatch = link.match(/\/d\/(.*?)\//);
if (!fileIdMatch) {
  throw new Error("Invalid Google Sheets link format");
}
const fileId = fileIdMatch[1];

// Extract GID (sheet/tab ID) from ?gid=xxxx or #gid=xxxx
const gidMatch = link.match(/gid=(\d+)/);
const gid = gidMatch ? gidMatch[1] : "0";  // default to first sheet if not found

// Construct direct CSV/XLSX export links for that specific sheet
const csvLink = `https://docs.google.com/spreadsheets/d/${fileId}/export?format=csv&gid=${gid}`;
const xlsxLink = `https://docs.google.com/spreadsheets/d/${fileId}/export?format=xlsx&gid=${gid}`;

return {
  json: {
    originalLink: link,
    fileId,
    gid,
    csvDownloadLink: csvLink,
    xlsxDownloadLink: xlsxLink
  }
};

const rows = items.map(i => i.json);
const toProcess = [];

for (let r of rows) {
  if ((r.toProcess || "").toUpperCase() === "TO_PROCESS") {
    toProcess.push({ json: r });
  }
}

return toProcess;

// items[0] = webhook node (contains csvLink in body.csv and optional sheetname)
// items[1..] = candidate responses

const webhookData = items[0].json;

// Extract CSV link and convert to direct download
const sheetLink = webhookData.body?.csv || null;
const sheetname = webhookData.body?.sheetName ; // default if not provided
let csvDownloadLink = null;

if (sheetLink) {
    const fileIdMatch = sheetLink.match(/\/d\/(.*?)\//);
    if (fileIdMatch) {
        const fileId = fileIdMatch[1];
        csvDownloadLink = `https://docs.google.com/spreadsheets/d/${fileId}/export?format=csv&gid=0`;
    }
}

// Process each candidate and attach csvLink and sheetname
const processedCandidates = items.slice(1).map(i => {
    return {
        json: {
            ...i.json,
            csvLink: csvDownloadLink,
            sheetname: sheetname

        }
    };
});

return processedCandidates;

// Collect all incoming items
const incoming = $input.all();

// Extract the prompt (from webhook body, assuming first item)
const prompt = incoming[0].json.body?.prompt || "";

// Build separate output items for each candidate
const results = [];

incoming.forEach((item, index) => {
  if (item.json.text && item.json.text.trim() !== "") {
    results.push({
      json: {
        prompt,
        candidate_id: index + 1,
        text: item.json.text
      }
    });
  }
});

// Return each candidate as its own item
return results;
